/**
 * Specifies the theme color of the Loader.
 * ([see example](components/indicators/loader/appearance#toc-theme-color)).
 *
 * The possible values are:
 * * `primary` (Default)&mdash;Applies coloring based on primary theme color.
 * * `secondary`&mdash;Applies coloring based on secondary theme color.
 * * `tertiary`&mdash; Applies coloring based on tertiary theme color.
 * * `base`&mdash; Applies coloring based on base theme color.
 *
 */
export type LoaderThemeColor = 'base' | 'primary' | 'secondary' | 'tertiary';
